namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Code { get; set; } = "";
    public string Name { get; set; } = "";
    public string Description { get; set; } = "";
}

namespace UniversityCourseCatalog.Models;

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Title { get; set; } = "";
    public string Bio { get; set; } = "";
    public string Email { get; set; } = "";
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = "";
    public string Title { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public int DepartmentId { get; set; }
    public Department Department { get; set; } = default!;
    public Instructor Instructor { get; set; } = default!;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = "";

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6-10 alphanumeric characters.")]
    public string StudentId { get; set; } = "";

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CourseCatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CourseCatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and language." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and fundamental forces." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and civilizations." }
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor of Computer Science", Bio = "Dr. Chen specializes in artificial intelligence and machine learning with over 15 years of research experience.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. Michael Roberts", Title = "Associate Professor of Computer Science", Bio = "Dr. Roberts focuses on software engineering and distributed systems.", Email = "m.roberts@university.edu" },
            new() { Id = 3, Name = "Dr. Emily Watson", Title = "Professor of Mathematics", Bio = "Dr. Watson is an expert in abstract algebra and number theory.", Email = "e.watson@university.edu" },
            new() { Id = 4, Name = "Dr. James Park", Title = "Associate Professor of Mathematics", Bio = "Dr. Park specializes in applied mathematics and statistical modeling.", Email = "j.park@university.edu" },
            new() { Id = 5, Name = "Dr. Linda Foster", Title = "Professor of English", Bio = "Dr. Foster is a renowned scholar of Victorian literature and creative writing.", Email = "l.foster@university.edu" },
            new() { Id = 6, Name = "Dr. Robert Kim", Title = "Associate Professor of English", Bio = "Dr. Kim researches modern American poetry and rhetoric.", Email = "r.kim@university.edu" },
            new() { Id = 7, Name = "Dr. Anna Martinez", Title = "Professor of Physics", Bio = "Dr. Martinez conducts research in quantum mechanics and particle physics.", Email = "a.martinez@university.edu" },
            new() { Id = 8, Name = "Dr. David Thompson", Title = "Associate Professor of Physics", Bio = "Dr. Thompson specializes in astrophysics and cosmology.", Email = "d.thompson@university.edu" },
            new() { Id = 9, Name = "Dr. Karen Williams", Title = "Professor of History", Bio = "Dr. Williams is an expert in European medieval history.", Email = "k.williams@university.edu" },
            new() { Id = 10, Name = "Dr. Thomas Brown", Title = "Associate Professor of History", Bio = "Dr. Brown focuses on American Civil War history and reconstruction.", Email = "t.brown@university.edu" }
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "MWF 9:00-9:50 AM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = true },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures including arrays, linked lists, trees, and graphs. Algorithm design and analysis techniques.", Credits = 4, Schedule = "TTh 10:30-11:45 AM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = false },
            new() { Id = 3, Code = "CS 301", Title = "Software Engineering", Description = "Principles of software development including design patterns, testing, version control, and agile methodologies.", Credits = 3, Schedule = "MWF 1:00-1:50 PM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[1], IsFeatured = true },
            new() { Id = 4, Code = "CS 401", Title = "Artificial Intelligence", Description = "Introduction to AI concepts including search, knowledge representation, machine learning, and neural networks.", Credits = 3, Schedule = "TTh 2:00-3:15 PM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = false },

            // Mathematics
            new() { Id = 5, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "MWF 8:00-8:50 AM", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[2], IsFeatured = true },
            new() { Id = 6, Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications.", Credits = 3, Schedule = "TTh 9:00-10:15 AM", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[2], IsFeatured = false },
            new() { Id = 7, Code = "MATH 301", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "MWF 11:00-11:50 AM", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[3], IsFeatured = false },

            // English
            new() { Id = 8, Code = "ENG 101", Title = "College Composition", Description = "Develop skills in academic writing, critical reading, and argumentation.", Credits = 3, Schedule = "MWF 10:00-10:50 AM", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[4], IsFeatured = false },
            new() { Id = 9, Code = "ENG 201", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present.", Credits = 3, Schedule = "TTh 1:00-2:15 PM", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[5], IsFeatured = false },
            new() { Id = 10, Code = "ENG 301", Title = "Creative Writing", Description = "Workshop-based course covering fiction, poetry, and creative nonfiction.", Credits = 3, Schedule = "MWF 2:00-2:50 PM", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[4], IsFeatured = true },

            // Physics
            new() { Id = 11, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based approach with laboratory component.", Credits = 4, Schedule = "MWF 9:00-9:50 AM, Lab: F 2:00-4:50 PM", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[6], IsFeatured = false },
            new() { Id = 12, Code = "PHYS 201", Title = "General Physics II", Description = "Electricity, magnetism, optics, and modern physics. Continuation of PHYS 101.", Credits = 4, Schedule = "TTh 10:30-11:45 AM, Lab: W 2:00-4:50 PM", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[6], IsFeatured = false },
            new() { Id = 13, Code = "PHYS 301", Title = "Quantum Mechanics", Description = "Introduction to quantum theory including wave functions, operators, and the Schrödinger equation.", Credits = 3, Schedule = "MWF 3:00-3:50 PM", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[7], IsFeatured = true },

            // History
            new() { Id = 14, Code = "HIST 101", Title = "World History I", Description = "Survey of world civilizations from prehistory through the Renaissance.", Credits = 3, Schedule = "MWF 10:00-10:50 AM", DepartmentId = 5, Department = _departments[4], Instructor = _instructors[8], IsFeatured = false },
            new() { Id = 15, Code = "HIST 201", Title = "American History", Description = "Comprehensive study of American history from colonization to the present day.", Credits = 3, Schedule = "TTh 11:00 AM-12:15 PM", DepartmentId = 5, Department = _departments[4], Instructor = _instructors[9], IsFeatured = false },
            new() { Id = 16, Code = "HIST 301", Title = "Medieval European History", Description = "In-depth study of European society, culture, and politics from the 5th to 15th centuries.", Credits = 3, Schedule = "TTh 3:30-4:45 PM", DepartmentId = 5, Department = _departments[4], Instructor = _instructors[8], IsFeatured = false }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public List<Course> GetCourses(string? search, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollment(EnrollmentRequest request)
    {
        var course = _courses.FirstOrDefault(c => c.Id == request.CourseId);
        return course != null;
    }
}

