@page "/courses"
@inject CourseCatalogService CatalogService

<PageTitle>Course Catalog - Greenfield University</PageTitle>

<h1 class="mb-4">Course Catalog</h1>

<form method="get" action="/courses" class="row g-3 mb-4">
    <div class="col-md-5">
        <input type="text" class="form-control" name="Search" value="@Search" placeholder="Search courses..." />
    </div>
    <div class="col-md-4">
        <select class="form-select" name="DepartmentId">
            <option value="">All Departments</option>
            @foreach (var dept in CatalogService.GetDepartments())
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@{
    var courses = CatalogService.GetCourses(Search, DepartmentId);
}

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.Department.Name</td>
                    <td>@course.Credits</td>
                    <td>@course.Schedule</td>
                    <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }
}

@page "/enroll"
@inject CourseCatalogService CatalogService

<PageTitle>Enrollment Request - Greenfield University</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Enrollment Submitted!</h4>
        <p>Thank you, <strong>@FormModel.StudentName</strong>. Your enrollment request for
        <strong>@(CatalogService.GetCourse(FormModel.CourseId)?.Title)</strong> has been received.</p>
        <p class="mb-0">Your Student ID: @FormModel.StudentId</p>
    </div>
    <a href="/courses" class="btn btn-primary">Browse More Courses</a>
}
else
{
    <EditForm Model="FormModel" method="post" OnValidSubmit="HandleSubmit" FormName="enrollment">
        <DataAnnotationsValidator />
        <AntiforgeryToken />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <InputText id="studentName" class="form-control" @bind-Value="FormModel.StudentName" />
            <ValidationMessage For="() => FormModel.StudentName" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" class="form-control" @bind-Value="FormModel.StudentId" />
            <small class="form-text text-muted">6-10 alphanumeric characters (uppercase)</small>
            <ValidationMessage For="() => FormModel.StudentId" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" class="form-select" @bind-Value="FormModel.CourseId">
                <option value="0">-- Select a course --</option>
                @foreach (var course in CatalogService.GetCourses(null, null))
                {
                    <option value="@course.Id">@course.Code - @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => FormModel.CourseId" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest FormModel { get; set; } = new();

    private bool submitted;

    private void HandleSubmit()
    {
        CatalogService.SubmitEnrollment(FormModel);
        submitted = true;
    }
}

@page "/courses"
