@page "/enroll"
@inject CourseCatalogService CatalogService

<PageTitle>Enrollment Request - Greenfield University</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Enrollment Submitted!</h4>
        <p>Thank you, <strong>@FormModel.StudentName</strong>. Your enrollment request for
        <strong>@(CatalogService.GetCourse(FormModel.CourseId)?.Title)</strong> has been received.</p>
        <p class="mb-0">Your Student ID: @FormModel.StudentId</p>
    </div>
    <a href="/courses" class="btn btn-primary">Browse More Courses</a>
}
else
{
    <EditForm Model="FormModel" method="post" OnValidSubmit="HandleSubmit" FormName="enrollment">
        <DataAnnotationsValidator />
        <AntiforgeryToken />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <InputText id="studentName" class="form-control" @bind-Value="FormModel.StudentName" />
            <ValidationMessage For="() => FormModel.StudentName" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" class="form-control" @bind-Value="FormModel.StudentId" />
            <small class="form-text text-muted">6-10 alphanumeric characters (uppercase)</small>
            <ValidationMessage For="() => FormModel.StudentId" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" class="form-select" @bind-Value="FormModel.CourseId">
                <option value="0">-- Select a course --</option>
                @foreach (var course in CatalogService.GetCourses(null, null))
                {
                    <option value="@course.Id">@course.Code - @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => FormModel.CourseId" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest FormModel { get; set; } = new();

    private bool submitted;

    private void HandleSubmit()
    {
        CatalogService.SubmitEnrollment(FormModel);
        submitted = true;
    }
}

