 @page "/courses"
 @inject CourseCatalogService CatalogService

 <PageTitle>Course Catalog - Greenfield University</PageTitle>

 <h1 class="mb-4">Course Catalog</h1>

 <form method="get" action="/courses" class="row g-3 mb-4">
     <div class="col-md-5">
         <input type="text" class="form-control" name="Search" value="@Search" placeholder="Search courses..." />
     </div>
     <div class="col-md-4">
         <select class="form-select" name="DepartmentId">
             <option value="">All Departments</option>
             @foreach (var dept in CatalogService.GetDepartments())
             {
                 <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
             }
         </select>
     </div>
     <div class="col-md-3">
         <button type="submit" class="btn btn-primary w-100">Search</button>
     </div>
 </form>

 @{
     var courses = CatalogService.GetCourses(Search, DepartmentId);
 }

 @if (courses.Count == 0)
 {
     <div class="alert alert-info">No courses found matching your criteria.</div>
 }
 else
 {
     <table class="table table-striped">
         <thead>
             <tr>
                 <th>Code</th>
                 <th>Title</th>
                 <th>Department</th>
                 <th>Credits</th>
                 <th>Schedule</th>
                 <th></th>
             </tr>
         </thead>
         <tbody>
             @foreach (var course in courses)
             {
                 <tr>
                     <td>@course.Code</td>
                     <td>@course.Title</td>
                     <td>@course.Department.Name</td>
                     <td>@course.Credits</td>
                     <td>@course.Schedule</td>
                     <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                 </tr>
             }
         </tbody>
     </table>
 }

 @code {
     [SupplyParameterFromQuery]
     public string? Search { get; set; }

     [SupplyParameterFromQuery]
     public int? DepartmentId { get; set; }
 }

